const { task_type, target, payload, session_id } = $('📥 Input').first().json;
if (!task_type) throw new Error('task_type erforderlich (log_analysis|health_check|system_update|incident)');
const types = ['log_analysis','health_check','system_update','incident'];
if (!types.includes(task_type)) throw new Error(`Unbekannter task_type: ${task_type}`);
return { task_type, target: target || {}, payload: payload || {}, session_id: session_id || require('crypto').randomUUID(),
  routed_to: { log_analysis: 'Functional: Unified Log Analyser', health_check: 'Functional: Unified Health Checker',
    system_update: 'Functional: Unified System Updater', incident: 'Module: Master Incident Handler' }[task_type] };

const { task_type, target, payload, session_id, routed_to } = $input.first().json;
// Routing erfolgt im Master durch executeWorkflow-Node mit routed_to-Name
return { task_type, target, payload, session_id, routed_to };

const input = $('🔧 Route Task').first().json;
const result = $input.first().json;
return { exit_code: result?.exit_code || 'success', session_id: input.session_id,
  task_type: input.task_type, routed_to: input.routed_to,
  data: result?.data || result, timestamp: new Date().toISOString() };
